class Solution:
    def calculate(self, s: str) -> int:
        it, num, stack, sign = 0, 0, [], "+"
        while it < len(s):
            if s[it].isdigit():
                num = num * 10 + int(s[it])
            elif s[it] in "+-*/":
                if sign == "+":
                    stack.append(num)
                elif sign == "-":
                    stack.append(-num)
                elif sign == "*":
                    stack.append(stack.pop() * num)
                elif sign == "/":
                    stack.append(int(stack.pop() / num))
                num, sign = 0, s[it]
            it += 1
        if sign == "+":
            stack.append(num)
        elif sign == "-":
            stack.append(-num)
        return sum(stack)
